-- =====================================================================
-- Seed: Mentorados for "Médicos de Resultado" organization
-- Organization ID: a0000000-0000-4000-8000-000000000001
-- Run: docker exec -i cs-postgres psql -U cssystem -d cssystem < docker/postgres/04-mentorados-seed.sql
-- =====================================================================

-- Ensure unique constraint on email for idempotent inserts
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'mentorados_email_key') THEN
    ALTER TABLE mentorados ADD CONSTRAINT mentorados_email_key UNIQUE (email);
  END IF;
END $$;

ON CONFLICT (email) DO UPDATE SET
  organization_id = EXCLUDED.organization_id,
  nome_completo = EXCLUDED.nome_completo,
  telefone = EXCLUDED.telefone,
  cpf = EXCLUDED.cpf,
  endereco_completo = EXCLUDED.endereco_completo;

-- =====================================================================
-- Verify
-- =====================================================================
SELECT COUNT(*) AS total_mentorados FROM mentorados WHERE organization_id = 'a0000000-0000-4000-8000-000000000001';
